import{c as e}from"./app.39e71802.js";import{_ as c}from"./plugin-vue_export-helper.21dcd24c.js";const o={},d=e('<p>\u77E5\u6211\u8005\u8C13\u6211\u5FC3\u5FE7\uFF0C\u4E0D\u77E5\u6211\u8005\u8C13\u6211\u4F55\u6C42</p><h2 id="\u5F15\u8A00" tabindex="-1"><a class="header-anchor" href="#\u5F15\u8A00" aria-hidden="true">#</a> \u5F15\u8A00</h2><p>\u5982\u679C\u4F60\u5BF9Vue.js\u4E2D\u6570\u636E\u54CD\u5E94\u7684\u7B80\u5355\u5B9E\u73B0\u8FD8\u4E0D\u719F\u6089\u7684\u8BDD\uFF0C\u8BF7\u5728\u53C2\u770B\u672C\u6587\u4E4B\u524D\u5148\u8D77\u8EAB\u770B\u770B\u6211\u6628\u5929\u5199\u7684\u8BFB\u4E66\u7B14\u8BB0<a href="https://juejin.cn/post/7069312716371918879" target="_blank" rel="noopener noreferrer">Vue.js\u54CD\u5E94\u5F0F\u6570\u636E\u7684\u7B80\u5355\u5B9E\u73B0</a>\uFF0C\u56E0\u4E3A\u4ECA\u5929\u7684\u5185\u5BB9\u53EF\u4EE5\u8BF4\u662F\u5728\u6628\u5929\u5185\u5BB9\u7684\u57FA\u7840\u4E0A\u5BF9\u5B9E\u73B0\u6570\u636E\u54CD\u5E94\u6240\u4F5C\u7684\u8FDB\u4E00\u6B65\u63A2\u7A76\u4E0E\u5B8C\u5584\uFF0C\u4ECA\u5929\u6240\u6709\u7684\u4EE3\u7801\u6F14\u793A\u4E5F\u90FD\u662F\u57FA\u4E8E\u6628\u5929\u7684\u4EE3\u7801\u3002</p><h2 id="\u5206\u652F\u5207\u6362bug" tabindex="-1"><a class="header-anchor" href="#\u5206\u652F\u5207\u6362bug" aria-hidden="true">#</a> \u5206\u652F\u5207\u6362Bug</h2><p>\u9996\u5148\uFF0C\u6211\u4EEC\u6765\u770B\u770B\u5728\u6570\u636E\u54CD\u5E94\u4E2D\uFF0C\u4EC0\u4E48\u53EB\u505A\u5206\u652F\u5207\u6362\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/09763493de904d93821754042c4ac1aa~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (48).png"></p><p>\u5982\u4E0A\u56FE\u6240\u793A\uFF0C\u5F53<code>obj.ok</code>\u5E03\u5C14\u503C\u53D8\u5316\u65F6\uFF0C\u526F\u4F5C\u7528\u51FD\u6570<code>effectFn</code>\u6240\u4F9D\u8D56\u7684\u6570\u636E\u4E5F\u4F1A\u968F\u4E4B\u53D8\u5316\uFF0C\u5373\u4EE3\u7801\u7684\u6267\u884C\u4F1A\u53D1\u751F\u53D8\u5316\uFF0C\u8FD9\u5C31\u662F\u672C\u6587\u6240\u6307\u7684<strong>\u5206\u652F\u5207\u6362</strong>\u3002</p><p>\u56DE\u987E\u4E00\u4E0B\u6628\u5929\u6240\u5B9E\u73B0\u7684\u7B80\u5355\u6570\u636E\u54CD\u5E94\uFF0C\u4F60\u4F1A\u53D1\u73B0<strong>\u5206\u652F\u5207\u6362</strong>\u4F1A\u4EA7\u751F\u9057\u7559\u7684\u526F\u4F5C\u7528\u51FD\u6570\u3002\u4EE5\u4E0A\u56FE\u4EE3\u7801\u4E3E\u4F8B\uFF0C\u5F53<code>data.ok == true</code>\u65F6\uFF0C\u526F\u4F5C\u7528\u51FD\u6570<code>effectFn</code>\u4F1A\u4E0E\u54CD\u5E94\u5F0F\u6570\u636E\u5BF9\u8C61<code>obj</code>\u7684<code>text</code>\u5C5E\u6027\u5EFA\u7ACB\u660E\u786E\u7684\u8054\u7CFB\uFF1A\u6BCF\u6B21\u4FEE\u6539<code>obj.text</code>\u90FD\u4F1A\u91CD\u65B0\u6267\u884C\u4E00\u6B21<code>effectFn</code>\u3002\u5230\u73B0\u5728\u4E3A\u6B62\uFF0C\u597D\u50CF\u8FD8\u6CA1\u53D1\u73B0\u4EC0\u4E48\u95EE\u9898\u3002\u4F46\u5982\u679C\uFF0C\u6B64\u65F6\u6267\u884C\u4EE3\u7801<code>obj.ok = false</code>\u4FEE\u6539\u4E86<code>obj.ok</code>\u7684\u503C\u65F6\uFF0C\u610F\u5916\u53D1\u751F\u4E86\uFF01</p><p>\u7406\u8BBA\u4E0A\uFF0C\u56E0\u4E3A\u6B64\u65F6<code>obj.ok</code>\u7684\u503C\u4E3A<code>false</code>\uFF0C\u6240\u4EE5<code>obj.text</code>\u503C\u7684\u4FEE\u6539\u4E0D\u5E94\u8BE5\u518D\u89E6\u53D1\u526F\u4F5C\u7528\u51FD\u6570<code>effectFn</code>\u7684\u6267\u884C\uFF1B\u4F46\u5728\u5B9E\u9645\u6D4B\u8BD5\u4E2D\uFF0C\u51FD\u6570<code>effectFn</code>\u5374\u6267\u884C\u4E86\u3002\u539F\u56E0\u5F88\u7B80\u5355\uFF1A\u65E9\u5728<code>obj.ok == true</code>\u7684\u65F6\u5019\uFF0C<code>effectFn</code>\u5C31\u4E0E<code>obj.text</code>\u5EFA\u7ACB\u4E86\u660E\u786E\u7684\u8054\u7CFB\uFF0C\u867D\u7136\u540E\u6765\u5C06<code>obj.ok</code>\u7684\u503C\u4FEE\u6539\u4E3A<code>false</code>\uFF0C\u4F46\u662F<code>effectFn</code>\u4E0E<code>obj.text</code>\u7684\u8054\u7CFB\u5E76\u6CA1\u6709\u56E0\u6B64\u88AB\u5207\u65AD\u3002\u6240\u4EE5\u8981\u60F3\u4FEE\u590D\u8FD9\u4E2A\u6F0F\u6D1E\uFF0C\u5E94\u8BE5\u5728\u6BCF\u6B21<code>obj.ok</code>\u88AB\u4FEE\u6539\u4E3A<code>false</code>\u7684\u65F6\u5019\uFF0C\u5207\u65AD<code>effectFn</code>\u4E0E<code>obj.text</code>\u7684\u8054\u7CFB\u3002\u90A3\uFF0C\u5982\u4F55\u5B9E\u73B0\u5462\uFF1F</p><p>\u5176\u5B9E\u89E3\u51B3\u601D\u8DEF\u5F88\u7B80\u5355\uFF1A\u5728\u6BCF\u6B21\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u524D\uFF0C\u628A\u5B83\u4ECE\u6240\u6709\u4E0E\u4E4B\u5173\u8054\u7684\u4F9D\u8D56\u96C6\u5408\u4E2D\u5220\u9664\uFF1B\u800C\u6BCF\u5F53\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u5B8C\u6BD5\u540E\uFF0C\u518D\u4E0E\u4F9D\u8D56\u9879\u5EFA\u7ACB\u65B0\u7684\u8054\u7CFB\u3002\u987A\u7740\u8FD9\u4E2A\u601D\u8DEF\uFF0C\u6211\u4EEC\u9700\u8981\u91CD\u65B0\u5B9A\u4E49\u526F\u4F5C\u7528\u51FD\u6570\u6CE8\u518C\u51FD\u6570<code>effect</code>\uFF0C\u5728\u5176\u4E2D\u5B9E\u73B0\u4E3A\u5F53\u524D\u7684\u526F\u4F5C\u7528\u51FD\u6570\u5173\u8054\u4E00\u4E2A\u6570\u7EC4\u7528\u6765\u50A8\u5B58\u6240\u6709\u5305\u542B\u8BE5\u526F\u4F5C\u7528\u51FD\u6570\u7684\u4F9D\u8D56\u96C6\u5408\uFF0C\u4EE3\u7801\u5982\u4E0B\uFF1A</p><ul><li>\u91CD\u65B0\u5B9A\u4E49<code>effect</code></li></ul><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/54723907fd5f49dbaa02676fbe925b2c~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (50).png"></p><ul><li><code>cleanup</code>\u51FD\u6570\u5B9E\u73B0</li></ul><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/2f5eec99a3f64a4580f48e339daee3e8~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (51).png"></p><ul><li><code>track</code> \u51FD\u6570\u4FEE\u6B63-\u6536\u96C6\u5F53\u524D\u526F\u4F5C\u7528\u51FD\u6570\u7684\u4F9D\u8D56\u96C6\u5408</li></ul><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/c2baf14473e64faf8fd4b160330c2c80~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (52).png"></p><p>\u81F3\u6B64\uFF0C\u6211\u4EEC\u5B9E\u73B0\u7684\u54CD\u5E94\u7CFB\u7EDF\u5DF2\u7ECF\u6210\u529F\u89E3\u51B3\u4E86<strong>\u5206\u652F\u5207\u6362</strong>\u5BFC\u81F4\u7684\u526F\u4F5C\u7528\u51FD\u6570\u9057\u7559\u95EE\u9898\u4E86\uFF0C\u662F\u4E0D\u662F\u611F\u89C9\u5927\u529F\u544A\u6210\u4E86\uFF1F\u8BD5\u4E00\u8BD5\u8FD0\u884C\u6D4B\u8BD5\u4E00\u4E0B\uFF1F\u563F\uFF0C\u70B8\u4E86\uFF0C\u65E0\u9650\u5FAA\u73AF\u4E86\uFF01\u5728\u524D\u6587\u4E2D\uFF0C\u6211\u4EEC\u4FEE\u6539\u4E86\u51FD\u6570<code>effect</code>\u3001<code>track</code>\uFF0C\u6DFB\u52A0\u4E86\u51FD\u6570<code>cleanup</code>\uFF0C\u4F46\u662F<code>trigger</code>\u51FD\u6570\u6211\u4EEC\u6CA1\u6709\u78B0\u8FC7\u3002\u8BF7\u6CE8\u610F\uFF0C\u6BCF\u6B21\u5BF9\u4EE3\u7801\u7684\u4FEE\u6539\u90FD\u8BF7\u8003\u8651\u5230\u662F\u5426\u4F1A\u5BF9\u5176\u4ED6\u90E8\u5206\u9020\u6210\u5F71\u54CD\u3002</p><p>\u8FD9\u6B21\u7684\u95EE\u9898\u5C31\u51FA\u5728<code>trigger</code>\u51FD\u6570\u4E0A\uFF0C\u8BF7\u770B\u6E90\u7801\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/bc6f9533b6674e32862a83b435b20ef7~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (53).png"></p><p>\u7528<code>forEach</code>\u904D\u5386\u96C6\u5408<code>effects</code>\u672C\u6765\u662F\u6CA1\u6709\u95EE\u9898\u7684\uFF08\u8FD9\u4E2A<code>effects</code>\u5C31\u662F\u524D\u9762\u7684<code>deps</code>\uFF09\uFF0C\u4F46\u662F\uFF0C\u524D\u6587\u4E0D\u662F\u8BF4\u4E86\u561B\uFF1A\u8981\u60F3\u89E3\u51B3<strong>\u5206\u652F\u5207\u6362</strong>\u7684\u95EE\u9898\uFF0C\u5C31\u8981\u5728\u5F53\u524D\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u524D\u5148\u8C03\u7528<code>cleanup</code>\u51FD\u6570\u6E05\u9664\uFF0C\u5373\u6267\u884C<code>deps.delete(effect)</code>\uFF1B\u800C\u5728\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u5B8C\u6BD5\u540E\uFF0C\u5F53\u524D\u526F\u4F5C\u7528\u51FD\u6570\u53C8\u4F1A\u4E0E\u4F9D\u8D56\u9879\u91CD\u65B0\u5EFA\u7ACB\u8054\u7CFB\uFF0C\u5373\u6267\u884C\u4E86<code>deps.add(effect)</code>\u3002\u8FD9\u4E00\u5220\u4E00\u6DFB\uFF0C\u5C31\u6CA1\u5B8C\u6CA1\u4E86\u4E86\uFF0C<code>forEach</code>\u6C38\u8FDC\u90FD\u904D\u5386\u4E0D\u5B8C\uFF0C\u5F53\u7136\u6B7B\u5FAA\u73AF\u5566~\u7B80\u5355\u76F4\u89C2\u7684\u4EE3\u7801\u4F53\u73B0\u5982\u4E0B\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/3ac27b7d37304756b509b23f02a7a271~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (54).png"></p><p>\u5982\u679C\u4F60\u6709\u7ECF\u9A8C\u7684\u8BDD\uFF0C\u4F60\u4F1A\u9A6C\u4E0A\u60F3\u5230\u89E3\u51B3\u529E\u6CD5\uFF1A\u53E6\u5916\u6784\u9020\u4E00\u4E2A\u96C6\u5408Set()\u7528\u6765\u904D\u5386\u5C31\u884C\u4E86\uFF0C<code>trigger</code>\u51FD\u6570\u4FEE\u6539\u540E\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6be423a07be24d6389ebf40dc6780f31~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (55).png"></p><h2 id="\u526F\u4F5C\u7528\u51FD\u6570\u5D4C\u5957bug" tabindex="-1"><a class="header-anchor" href="#\u526F\u4F5C\u7528\u51FD\u6570\u5D4C\u5957bug" aria-hidden="true">#</a> \u526F\u4F5C\u7528\u51FD\u6570\u5D4C\u5957Bug</h2><p>\u5982\u679C\u6211\u5728\u4E00\u4E2A\u526F\u4F5C\u7528\u51FD\u6570\u91CC\u518D\u5D4C\u5957\u4E00\u4E2A\u526F\u4F5C\u7528\u51FD\u6570\uFF0C\u5982\u4E0B\u6240\u793A\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/8bca5836097549289fb34f0b069906b2~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (57).png"></p><p>\u7406\u60F3\u60C5\u51B5\u4E0B\uFF0C\u6211\u4EEC\u5E0C\u671B\u6BCF\u6B21\u4FEE\u6539<code>obj.foo</code>\u90FD\u4F1A\u6267\u884C<code>effectFn1</code>\u4EE5\u53CA<code>effectFn2</code>\uFF0C\u800C\u5F53\u4FEE\u6539<code>obj.bar</code>\u65F6\u53EA\u6267\u884C<code>effectFn2</code>\u3002\u4F46\u662F\u4E8B\u5B9E\u4E0A\u662F\u8FD9\u6837\u5417\uFF1F\u8BFB\u8005\u5927\u53EF\u81EA\u5DF1\u8BD5\u4E00\u8BD5\u3002\u4E8B\u5B9E\u4E0A\uFF0C\u5F53\u518D\u6B21\u4FEE\u6539<code>obj.foo</code>\u7684\u503C\u65F6\uFF0C\u53EA\u6709<code>effectFn2</code>\u6267\u884C\u4E86\uFF0C\u8FD9\u663E\u7136\u662F\u4E0D\u7B26\u5408\u9884\u671F\u7684\u3002</p><p>\u90A3\u95EE\u9898\u51FA\u5728\u54EA\u91CC\u5462\uFF1F\u4E0D\u77E5\u9053\u8BFB\u8005\u662F\u5426\u8FD8\u8BB0\u5F97\u6211\u4EEC\u5148\u524D\u662F\u600E\u4E48\u50A8\u5B58\u5F53\u524D\u526F\u4F5C\u7528\u51FD\u6570\u7684\uFF0C\u6211\u4EEC\u7528\u7684\u662F<code>activeEffect</code>\uFF0C\u663E\u7136\uFF0C\u540C\u4E00\u65F6\u523B<code>activeEffect</code>\u53EA\u80FD\u50A8\u5B58\u4E00\u4E2A\u526F\u4F5C\u7528\u51FD\u6570\uFF0C\u90A3\u5F53\u526F\u4F5C\u7528\u51FD\u6570\u53D1\u751F\u5D4C\u5957\u65F6\uFF0C\u5185\u90E8\u7684\u526F\u4F5C\u7528\u51FD\u6570\u5C31\u4F1A\u8986\u76D6\u6389\u5916\u90E8\u7684\u526F\u4F5C\u7528\u51FD\u6570\uFF0C\u8FD9\u4F1A\u4F7F\u539F\u672C\u5E94\u8BE5\u4E0E\u5916\u5C42\u526F\u4F5C\u7528\u51FD\u6570\u5EFA\u7ACB\u8054\u7CFB\u7684\u54CD\u5E94\u5F0F\u6570\u636E\u6536\u96C6\u5230\u7684\u526F\u4F5C\u7528\u51FD\u6570\u53D8\u6210\u4E86\u5185\u5C42\u7684\u526F\u4F5C\u7528\u51FD\u6570\u3002</p><p>\u600E\u4E48\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\u5462\uFF1F\u6211\u4EEC\u53EF\u4EE5\u5B9A\u4E49\u4E00\u4E2A\u6A21\u62DF\u6808\u7684\u6570\u7EC4<code>effectStack</code>\uFF0C\u81F3\u4E8E<code>activeEffect</code>\u5219\u4FDD\u6301\u4E0D\u53D8\uFF0C\u8FD9\u6837\uFF0C\u5F53\u53D1\u751F\u526F\u4F5C\u7528\u51FD\u6570\u5D4C\u5957\u65F6\uFF0C\u4F1A\u5148\u5C06\u5916\u5C42\u526F\u4F5C\u7528\u51FD\u6570\u538B\u5165\u6808\u5E95\uFF0C\u800C\u6700\u5185\u5C42\u526F\u4F5C\u7528\u51FD\u6570\u4F1A\u88AB\u538B\u5165\u6808\u9876\uFF0C<code>activeEffect</code>\u5219\u6C38\u8FDC\u6307\u5411\u6808\u9876\u5143\u7D20\u4EE3\u7801\u5B9E\u73B0\u5982\u4E0B\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/793de65d83b6417489e5e2ed1ab0932c~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (58).png"></p><h2 id="\u65E0\u9650\u9012\u5F52\u5FAA\u73AFbug" tabindex="-1"><a class="header-anchor" href="#\u65E0\u9650\u9012\u5F52\u5FAA\u73AFbug" aria-hidden="true">#</a> \u65E0\u9650\u9012\u5F52\u5FAA\u73AFbug</h2><p>\u6211\u627F\u8BA4\uFF0C\u6211\u5C31\u662F\u6765\u627E\u832C\u7684\uFF0C\u5C31\u770B\u4F60\u80FD\u4E0D\u80FD\u63A5\u4F4F\u4E86\uFF0C\u793A\u4F8B\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p1-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/360bb433739b47529bff31e7c83a7229~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (59).png"></p><p>\u8FD9\u79CD\u60C5\u51B5\u4F1A\u76F4\u63A5\u5BFC\u81F4\u6808\u6EA2\u51FA\uFF0C\u5206\u6790\u5982\u4E0B\uFF1A<code>obj.foo++</code>\u65E2\u4F1A\u8BFB\u53D6<code>obj.foo</code>\u7684\u503C\u89E6\u53D1<code>track</code>\uFF0C\u4ECE\u800C\u5C06\u5F53\u524D\u526F\u4F5C\u7528\u51FD\u6570\u6536\u96C6\u5230<code>bucket</code>\u4E2D\uFF1B\u7D27\u63A5\u7740\u53C8\u8BBE\u7F6E<code>obj.foo</code>\u7684\u503C\uFF0C\u89E6\u53D1<code>trigger</code>\u6267\u884C\u521A\u653E\u5165<code>bucket</code>\u4E2D\u7684\u526F\u4F5C\u7528\u51FD\u6570\u3002\u800C\u5F88\u4E0D\u5DE7\u7684\u662F\uFF0C\u6B64\u65F6\u5BFC\u81F4\u8BE5\u73B0\u8C61\u7684\u526F\u4F5C\u7528\u51FD\u6570\u672C\u8EAB\u90FD\u8FD8\u6CA1\u6709\u6267\u884C\u5B8C\u6BD5\u5462\uFF0C\u8FD9\u5C31\u5BFC\u81F4\u4E86\u526F\u4F5C\u7528\u51FD\u6570\u65E0\u9650\u8C03\u7528\u81EA\u5DF1\uFF0C\u4EA7\u751F\u6808\u6EA2\u51FA\u3002\u5C31\u597D\u6BD4\u7528\u9012\u5F52\u6216\u8005\u8FED\u4EE3\u5199\u4E2A\u7B97\u6CD5\u9898\uFF0C\u7ED3\u679C\u6CA1\u8BBE\u7F6E<code>return</code>\u51FA\u53E3\uFF0C\u76F4\u63A5\u73A9\u5B8C\u3002</p><p>\u89E3\u51B3\u601D\u8DEF\u4E5F\u4E0D\u96BE\uFF0C\u6709\u70B9\u7C7B\u4F3C<strong>\u8282\u6D41</strong>\uFF1A\u5F53<code>trigger</code>\u89E6\u53D1\u7684\u526F\u4F5C\u7528\u51FD\u6570\u4E0E\u5F53\u524D\u6B63\u5728\u6267\u884C\u7684\u526F\u4F5C\u7528\u51FD\u6570\u76F8\u540C\uFF0C\u5219\u4E0D\u89E6\u53D1\u6267\u884C\u3002\u4FEE\u6539\u540E\u7684<code>trigger</code>\u51FD\u6570\u5982\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/328144c1f03d4a24913ea54df03d1ddd~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (60).png"></p><h2 id="\u6DFB\u52A0\u8C03\u5EA6\u6267\u884C\u529F\u80FD" tabindex="-1"><a class="header-anchor" href="#\u6DFB\u52A0\u8C03\u5EA6\u6267\u884C\u529F\u80FD" aria-hidden="true">#</a> \u6DFB\u52A0\u8C03\u5EA6\u6267\u884C\u529F\u80FD</h2><p><strong>\u53EF\u8C03\u5EA6</strong>\u6307\u7684\u662F\u5F53<code>trigger</code>\u52A8\u4F5C\u89E6\u53D1\u526F\u4F5C\u7528\u51FD\u6570\u91CD\u65B0\u6267\u884C\u65F6\uFF0C\u6709\u80FD\u529B\u51B3\u5B9A\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u7684\u65F6\u673A\u3001\u6B21\u6570\u4EE5\u53CA\u65B9\u5F0F\u3002\u53EF\u8C03\u5EA6\u6027\u662F\u54CD\u5E94\u5F0F\u7CFB\u7EDF\u4E00\u4E2A\u975E\u5E38\u91CD\u8981\u7684\u7279\u6027\uFF0C\u6BD4\u5982\u5728Vue.js\u4E2D\u8981\u60F3\u5B9E\u73B0\u201C\u8FDE\u7EED\u591A\u6B21\u4FEE\u6539\u54CD\u5E94\u5F0F\u6570\u636E\u4F46\u53EA\u89E6\u53D1\u4E00\u6B21\u66F4\u65B0\u201D\u8FD9\u4E2A\u529F\u80FD\uFF0C\u652F\u6301\u53EF\u8C03\u5EA6\u5C31\u662F\u5173\u952E\u6240\u5728\u3002\u53EF\u4EE5\u76F4\u767D\u5730\u8BF4\uFF0C<strong>\u53EF\u8C03\u5EA6</strong>\u5C31\u662F\u8BA9\u526F\u4F5C\u7528\u51FD\u6570\u53D7\u5230\u7528\u6237\u7684\u4E3B\u52A8\u63A7\u5236\uFF0C\u6839\u636E\u7528\u6237\u7684\u610F\u613F\u6765\u51B3\u5B9A\u5982\u4F55\u6267\u884C\u3002</p><p>\u4E3A\u4E86\u5B9E\u73B0\u8FD9\u4E2A\u529F\u80FD\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5728\u526F\u4F5C\u7528\u51FD\u6570\u6CE8\u518C\u7684\u65F6\u5019\u4E3A\u6BCF\u4E00\u4E2A\u526F\u4F5C\u7528\u51FD\u6570\u6DFB\u52A0\u4E00\u4E2A<code>options</code>\u5C5E\u6027\u7528\u6765\u63A5\u53D7\u7528\u6237\u4F20\u5165\u7684\u989D\u5916\u503C\uFF0C\u4ECE\u800C\u5B9E\u73B0\u8BA9\u7528\u6237\u81EA\u5DF1\u63A7\u5236\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u7684\u65F6\u673A\u3001\u6B21\u6570\u4EE5\u53CA\u65B9\u5F0F\u3002\u91CD\u65B0\u8BBE\u8BA1\u7684<code>effect</code>\u51FD\u6570\u5982\u4E0B\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/ac28e698e30f4daf8e8b3994d2238a3b~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (61).png"></p><p>\u5BF9<code>trigger</code>\u505A\u76F8\u5E94\u7684\u4FEE\u6539\u5982\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/11a585eebd924976a4cdf321ebe8c686~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (70).png"></p><p>\u81F3\u6B64\uFF0C\u6211\u4EEC\u5C31\u53EF\u4EE5\u81EA\u884C\u63A7\u5236\u526F\u4F5C\u7528\u51FD\u6570\u6267\u884C\u7684\u65F6\u673A\u3001\u6B21\u6570\u4EE5\u53CA\u65B9\u5F0F\uFF0C\u793A\u4F8B\u5982\u4E0B\uFF1B</p><p>\u539F\u4EE3\u7801\uFF1A</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/0965e517bf4a4ffdb300a819a3421f86~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (71).png"></p><p>\u73B0\u5728\uFF0C\u5047\u8BBE\u9700\u6C42\u6709\u53D8\uFF0C\u9700\u8981\u5148\u8F93\u51FA\u5B57\u7B26\u4E32<code>&#39;\u7ED3\u675F\u4E86&#39;</code>\uFF0C\u7136\u540E\u518D\u8F93\u51FA\u6570\u5B57<code>2</code>\u3002\u4E3A\u4E86\u5B9E\u73B0\u8FD9\u4E2A\u9700\u6C42\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5229\u7528\u9009\u9879\u53C2\u6570<code>options</code>\u8BBE\u8BA1\u4E00\u4E2A\u8C03\u5EA6\u5668\u51FD\u6570<code>scheduler</code>\uFF0C\u793A\u4F8B\u4EE3\u7801\u5982\u4E0B\uFF1A</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/3b11a69d19f343abb8605ec907b29d9b~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (67).png"></p><p>\u8FD9\u4E2A<code>scheduler</code>\u8C03\u5EA6\u5668\u51FD\u6570\u5C31\u662F\u5B9E\u73B0<strong>\u53EF\u8C03\u5EA6\u6027</strong>\u7684\u7CBE\u9AD3\u6240\u5728\uFF0C\u7528\u6237\u901A\u8FC7\u91CD\u6784<code>scheduler</code>\u51FD\u6570\uFF0C\u53EF\u4EE5\u6309\u7167\u81EA\u5DF1\u7684\u9700\u6C42\u6765\u8C03\u5EA6\u526F\u4F5C\u7528\u51FD\u6570\u7684\u6267\u884C\u3002</p><h2 id="\u603B\u7ED3" tabindex="-1"><a class="header-anchor" href="#\u603B\u7ED3" aria-hidden="true">#</a> \u603B\u7ED3</h2><p>\u81F3\u6B64\uFF0C\u6570\u636E\u54CD\u5E94\u7684\u5B9E\u73B0\u53CA\u5B8C\u5584\u57FA\u672C\u4ECB\u7ECD\u5B8C\u6BD5\uFF0C\u5728\u6B64\u9644\u4E0A\u5B8C\u6574\u4EE3\u7801\uFF1A</p><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/67efae0af7714ad7a2c9fe90de853ccd~tplv-k3u1fbpfcp-watermark.image?" alt="carbon (69).png"></p><h2 id="\u540E\u8BDD" tabindex="-1"><a class="header-anchor" href="#\u540E\u8BDD" aria-hidden="true">#</a> \u540E\u8BDD</h2><p>\u6211\u6700\u8FD1\u5199\u7684\u8BFB\u6570\u7B14\u8BB0\u90FD\u8D34\u4E86\u4E0D\u5C11\u300AVue.js\u8BBE\u8BA1\u4E0E\u5B9E\u73B0\u300B\u4E66\u4E0A\u7684\u4EE3\u7801\uFF0C\u5176\u5B9E\u611F\u89C9\u5728\u6587\u7AE0\u91CC\u4EE3\u7801\u56FE\u7247\u7684\u91CF\u4E00\u591A\u786E\u5B9E\u4E0D\u8BA8\u559C\u3002\u4F46\u662F\uFF0C\u6211\u89C9\u5F97\u8FD9\u662F\u6709\u5FC5\u8981\u7684\u3002\u56E0\u4E3A\u6211\u89C9\u5F97\u4EE3\u7801\u6BD4\u6587\u5B57\u8868\u73B0\u7684\u66F4\u52A0\u76F4\u89C2\uFF0C\u751A\u81F3\u8003\u8651\u5230\u8BFB\u8005\u5728\u770B\u4E0D\u61C2\u6216\u8005\u8FD8\u4E0D\u719F\u6089\u7684\u5730\u65B9\u5E94\u8BE5\u5BF9\u7740\u6211\u9644\u4E0A\u7684\u4EE3\u7801\u591A\u6572\u51E0\u904D\uFF0C\u6BD5\u7ADF\uFF0C\u6A21\u4EFF\u5B66\u4E60\u5728\u67D0\u79CD\u7A0B\u5EA6\u4E0A\u662F\u6700\u9AD8\u6548\u7684\u3001\u5165\u95E8\u901F\u5EA6\u6700\u5FEB\u7684\u5B66\u4E60\u65B9\u5F0F\u3002</p>',53);function p(t,a){return d}var b=c(o,[["render",p]]);export{b as default};
